mapper.select:
SELECT eo.*, si.image_url AS item_image FROM exchange_order eo LEFT JOIN shop_item si ON eo.item_id = si.id WHERE eo.user_id = #{userId}
AND eo.item_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY eo.create_time DESC

mapper.update:
UPDATE exchange_order
SET status = #{status}, verify_time = #{verifyTime}, verify_admin_id = #{verifyAdminId}
WHERE id = #{id}
